-- Prisma baseline migration for AegisShield control-plane data
CREATE TABLE IF NOT EXISTS "Organization" ("id" TEXT PRIMARY KEY, "name" TEXT NOT NULL, "slug" TEXT UNIQUE NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "Tenant" ("id" TEXT PRIMARY KEY, "name" TEXT NOT NULL, "tenantKey" TEXT UNIQUE NOT NULL, "organizationId" TEXT NOT NULL REFERENCES "Organization"("id"), "createdAt" TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "Project" ("id" TEXT PRIMARY KEY, "tenantId" TEXT NOT NULL REFERENCES "Tenant"("id"), "name" TEXT NOT NULL, "slug" TEXT NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "Environment" ("id" TEXT PRIMARY KEY, "projectId" TEXT NOT NULL REFERENCES "Project"("id"), "type" TEXT NOT NULL, "name" TEXT NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "User" ("id" TEXT PRIMARY KEY, "organizationId" TEXT NOT NULL REFERENCES "Organization"("id"), "email" TEXT UNIQUE NOT NULL, "fullName" TEXT NOT NULL, "passwordHash" TEXT NOT NULL, "role" TEXT NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "ApiKey" ("id" TEXT PRIMARY KEY, "tenantId" TEXT NOT NULL REFERENCES "Tenant"("id"), "label" TEXT NOT NULL, "keyPrefix" TEXT NOT NULL, "secretHash" TEXT NOT NULL, "revokedAt" TIMESTAMP NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "DetectionEvent" ("id" TEXT PRIMARY KEY, "tenantId" TEXT NOT NULL REFERENCES "Tenant"("id"), "type" TEXT NOT NULL, "severity" INTEGER NOT NULL, "payload" JSONB NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "Alert" ("id" TEXT PRIMARY KEY, "tenantId" TEXT NOT NULL REFERENCES "Tenant"("id"), "ruleId" TEXT NOT NULL, "severity" INTEGER NOT NULL, "status" TEXT NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "ResponseAction" ("id" TEXT PRIMARY KEY, "tenantId" TEXT NOT NULL REFERENCES "Tenant"("id"), "actionType" TEXT NOT NULL, "status" TEXT NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "AuditLog" ("id" TEXT PRIMARY KEY, "tenantId" TEXT NOT NULL REFERENCES "Tenant"("id"), "actor" TEXT NOT NULL, "action" TEXT NOT NULL, "metadata" JSONB NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "PolicyBundle" ("id" TEXT PRIMARY KEY, "tenantId" TEXT NOT NULL REFERENCES "Tenant"("id"), "version" TEXT NOT NULL, "signature" TEXT NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "Subscription" ("id" TEXT PRIMARY KEY, "organizationId" TEXT NOT NULL REFERENCES "Organization"("id"), "plan" TEXT NOT NULL, "status" TEXT NOT NULL, "graceUntil" TIMESTAMP NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT NOW());
